// 1. Definição do dicionário de mensagens conforme sua especificação
const mapaMensagens = [
    "Robô em Home",          // Índice 0
    "Robô em sleep",         // Índice 1
    "Robô em movimento",     // Índice 2
    "Rampa 1 em execução",   // Índice 3
    "Rampa 2 em execução",   // Índice 4
    "Rampa 3 em execução"    // Índice 5
];

// 2. O payload recebido (ex: msg.payload = [true, false, true...])
const entradasDigitais = msg.payload;

// 3. Filtramos quais posições estão 'true' e mapeamos para o texto
// Se houver mais de um true, ele retornará todas as mensagens ativas separadas por vírgula
let mensagensAtivas = [];

for (let i = 0; i < mapaMensagens.length; i++) {
    if (entradasDigitais[i] === true || entradasDigitais[i] === 1) {
        mensagensAtivas.push(mapaMensagens[i]);
    }
}

// 4. Se nada estiver ativo, definimos um status padrão
const statusFinal = mensagensAtivas.length > 0 
    ? mensagensAtivas.join(" | ") 
    : "Robô em Standby";

// 5. Preparação do objeto para o Servidor SSE / Next.js
msg.payload = {
    status_robo: statusFinal,
    timestamp: new Date().toLocaleTimeString("pt-BR"),
    // Mantemos os valores brutos caso precise usar em lógica de cores no Next.js
    raw_bits: entradasDigitais 
};

return msg;
